function httpPost(url, headers, body) {
  return new Promise(function(resolve, reject) {
    const urlObj = new URL(url)
    const options = { hostname: urlObj.hostname, path: urlObj.pathname + urlObj.search, method: 'POST', headers: headers }
    const req = https.request(options, function(res) {
      let data = ''
      res.on('data', function(chunk) { data += chunk })
      res.on('end', function() { resolve({ status: res.statusCode, body: data }) })
    })
    req.on('error', reject)
    req.write(body)
    req.end()
  })
}

async function main() {
  if (!SUPABASE_URL || !SUPABASE_KEY) {
    console.log('Lance avec:')
    console.log('  set NEXT_PUBLIC_SUPABASE_URL=https://xxx.supabase.co')
    console.log('  set SUPABASE_SERVICE_KEY=eyJ...')
    console.log('  node import-fournitures-traction.js')
    return
  }
  console.log(FOURNITURES.length + ' fournitures Traction a importer...')
  let total = 0
  for (let i = 0; i < FOURNITURES.length; i += 500) {
    const batch = FOURNITURES.slice(i, i + 500)
    const body = JSON.stringify(batch)
    const headers = {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body),
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Prefer': 'return=minimal'
    }
    const res = await httpPost(SUPABASE_URL + '/rest/v1/fournitures_catalogue', headers, body)
    if (res.status >= 300) { console.log('ERREUR: ' + res.body) }
    else { total += batch.length; console.log(total + '/' + FOURNITURES.length + ' importees') }
  }
  console.log('Termine! ' + total + ' fournitures importees.')
}
main().catch(console.error)
